    await createUser('test-dup@example.com', 'password123');
    const result = await createUser('test-dup@example.com', 'password456');
    assert.ok('code' in result);
    if ('code' in result) {
      assert.equal(result.code, 'DUPLICATE_EMAIL');
    }
  });

