    const result = await createUser('not-an-email', 'password123');
    assert.ok('code' in result);
    if ('code' in result) {
      assert.equal(result.code, 'INVALID_INPUT');
    }
  });

  it('rejects short password', async () => {
    const result = await createUser('test-short@example.com', 'abc');
    assert.ok('code' in result);
    if ('code' in result) {
      assert.equal(result.code, 'INVALID_INPUT');
    }
  });
